import { styled } from '@mui/material/styles';
import { createTheme, ThemeProvider } from '@mui/material/styles';
import Card from '@mui/material/Card';
import Avatar from '@mui/material/Avatar';
import Typography from '@mui/material/Typography';

// Override theme cho Typography
const theme = createTheme({});

// Styled components cho Avatar và các text
const ProfileAvatar = styled(Avatar)({});
const Name = styled(Typography)({});
const Description = styled(Typography)({});

function ProfileCard() {
  return (
    <ThemeProvider theme={theme}>
      <Card sx={{ /* Layout styles */ }}>
        <ProfileAvatar src="/avatar.jpg" />
        <Name>John Doe</Name>
        <Description>Software Developer</Description>
      </Card>
    </ThemeProvider>
  );
}

export default ProfileCard;

codeExercises.solution:
import { styled } from '@mui/material/styles';
import { createTheme, ThemeProvider } from '@mui/material/styles';
import Card from '@mui/material/Card';
import Avatar from '@mui/material/Avatar';
import Typography from '@mui/material/Typography';

const theme = createTheme({
  components: {
    MuiTypography: {
      variants: [
        {
          props: { variant: 'h5' },
          style: { fontFamily: ''Georgia, serif'' },
        },
      ],
    },
  },
});

const ProfileAvatar = styled(Avatar)(({ theme }) => ({
  width: theme.spacing(10),
  height: theme.spacing(10),
  border: `2px solid ${theme.palette.primary.main}`,
}));

const Name = styled(Typography)({});

const Description = styled(Typography)(({ theme }) => ({
  color: theme.palette.text.secondary,
}));

function ProfileCard() {
  return (
    <ThemeProvider theme={theme}>
      <Card sx={{
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        gap: 2,
        p: 3,
        maxWidth: 300
      }}>
        <ProfileAvatar src="/avatar.jpg" />
        <Name variant="h5">John Doe</Name>
        <Description variant="body1">Software Developer</Description>
      </Card>
    </ThemeProvider>
  );
}

export default ProfileCard;
